import{_ as a,o as i,c as e,ag as t}from"./chunks/framework.CMYkYJvz.js";const k=JSON.parse('{"title":"桌面版安装与构建","description":"桌面版安装方式、本地构建步骤与常见注意事项。","frontmatter":{"title":"桌面版安装与构建","description":"桌面版安装方式、本地构建步骤与常见注意事项。","editLink":false},"headers":[],"relativePath":"getting-started/desktop.md","filePath":"getting-started/desktop.md"}'),l={name:"getting-started/desktop.md"};function n(d,s,p,o,h,r){return i(),e("div",null,[...s[0]||(s[0]=[t(`<blockquote><p>此页面由 <code>docs/desktop.md</code> 自动同步生成。</p></blockquote><h1 id="桌面版安装与构建" tabindex="-1">桌面版安装与构建 <a class="header-anchor" href="#桌面版安装与构建" aria-label="Permalink to &quot;桌面版安装与构建&quot;">​</a></h1><p>桌面版基于 Tauri 构建，安装包内已包含 Web 资源，并会在应用内部启动打包进去的 <code>bifrost</code> CLI 后端。</p><h2 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h2><h3 id="先选择正确安装包" tabindex="-1">先选择正确安装包 <a class="header-anchor" href="#先选择正确安装包" aria-label="Permalink to &quot;先选择正确安装包&quot;">​</a></h3><p>打开 <a href="https://github.com/bifrost-proxy/bifrost/releases" target="_blank" rel="noreferrer">Releases</a> 后，优先选择最新版本的 <code>Assets</code>。桌面端安装包文件名包含平台和架构：</p><table tabindex="0"><thead><tr><th>系统</th><th>该选哪个文件</th><th>适用设备</th></tr></thead><tbody><tr><td>macOS Apple Silicon</td><td><code>bifrost-desktop-vX.X.X-aarch64-apple-darwin.dmg</code></td><td>M1/M2/M3/M4 等 Apple Silicon Mac</td></tr><tr><td>macOS Intel</td><td><code>bifrost-desktop-vX.X.X-x86_64-apple-darwin.dmg</code></td><td>Intel Mac</td></tr><tr><td>Windows x64</td><td><code>bifrost-desktop-vX.X.X-x86_64-pc-windows-msvc.msi</code></td><td>大多数 Windows 笔记本和台式机</td></tr><tr><td>Windows ARM64</td><td><code>bifrost-desktop-vX.X.X-aarch64-pc-windows-msvc.msi</code></td><td>Windows on ARM 设备</td></tr></tbody></table><p>如果只是想使用命令行，不需要安装桌面端，直接使用 <a href="./installation"><code>getting-started.md</code></a> 中的 CLI 安装方式。</p><h3 id="homebrew-cask-macos" tabindex="-1">Homebrew Cask（macOS） <a class="header-anchor" href="#homebrew-cask-macos" aria-label="Permalink to &quot;Homebrew Cask（macOS）&quot;">​</a></h3><p>由于当前尚未签名，如需通过 Homebrew 安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tap</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-proxy/bifrost</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost-desktop</span></span></code></pre></div><p>如果不希望使用 Cask，推荐直接从源码执行 <code>./install.sh</code>，或使用 CLI 版本。</p><h3 id="手动下载安装包" tabindex="-1">手动下载安装包 <a class="header-anchor" href="#手动下载安装包" aria-label="Permalink to &quot;手动下载安装包&quot;">​</a></h3><p>可从 <a href="https://github.com/bifrost-proxy/bifrost/releases" target="_blank" rel="noreferrer">Releases</a> 下载桌面安装包。</p><h4 id="macos-dmg" tabindex="-1">macOS <code>.dmg</code> <a class="header-anchor" href="#macos-dmg" aria-label="Permalink to &quot;macOS \`.dmg\`&quot;">​</a></h4><ol><li>下载与你芯片匹配的 <code>.dmg</code>。</li><li>双击打开 <code>.dmg</code>。</li><li>将 <code>Bifrost.app</code> 拖入 <code>Applications</code>。</li><li>从 <code>Applications</code>、Launchpad 或 Spotlight 启动 Bifrost。</li><li>如果 macOS 提示应用来自互联网下载，确认打开；如果未签名版本被 Gatekeeper 拦截，到 <code>System Settings -&gt; Privacy &amp; Security</code> 中允许打开。</li></ol><h4 id="windows-msi" tabindex="-1">Windows <code>.msi</code> <a class="header-anchor" href="#windows-msi" aria-label="Permalink to &quot;Windows \`.msi\`&quot;">​</a></h4><ol><li>下载与你设备架构匹配的 <code>.msi</code>。</li><li>双击 <code>.msi</code>，按安装向导完成安装。</li><li>从 Start Menu 启动 <code>Bifrost</code>。</li><li>如果 Windows SmartScreen 提示未知发布者，确认安装包来自官方 GitHub Releases 后再继续。</li></ol><h2 id="首次启动" tabindex="-1">首次启动 <a class="header-anchor" href="#首次启动" aria-label="Permalink to &quot;首次启动&quot;">​</a></h2><p>安装完成后：</p><ul><li>macOS 启动 <code>Bifrost.app</code>。</li><li>Windows 从 Start Menu 启动 <code>Bifrost</code>。</li><li>桌面端会在应用内部启动打包的 <code>bifrost</code> 后端，不需要先手动执行 <code>bifrost start</code>。</li><li>默认数据目录为 <code>~/.bifrost</code>，桌面端和 CLI 默认共享这份配置、证书、日志和运行时状态。</li><li>桌面端首次启动会异步检查并安装 CA 证书；需要 HTTPS 抓包时，先确认系统已信任 Bifrost CA。</li><li>桌面端会在启动时检查更新，并最多每 6 小时自动检查一次；发现新版本后会显示右下角通知并打开更新窗口。</li></ul><p>如需改写 <code>config / certs / logs / runtime</code> 目录，可在启动前设置 <code>BIFROST_DATA_DIR</code>。普通用户日常使用不建议改写数据目录，除非你要隔离测试环境或调试多实例。</p><h2 id="桌面端与-cli-的关系" tabindex="-1">桌面端与 CLI 的关系 <a class="header-anchor" href="#桌面端与-cli-的关系" aria-label="Permalink to &quot;桌面端与 CLI 的关系&quot;">​</a></h2><p>桌面端内置一个 <code>bifrost</code> 后端，用于支撑当前 App 的代理、规则、流量和设置页面。你仍然可以单独安装 CLI，用于终端、脚本、CI 或 AI coding tools。</p><p>如果你先安装的是桌面端，可以在桌面 Settings 的 <code>Desktop Proxy Core</code> 卡片里点击 <code>Install CLI &amp; Skills</code>。该按钮会：</p><ul><li>把桌面端内置的 <code>bifrost</code> CLI 安装到用户命令行目录。</li><li>安装 Bifrost AI skills，方便 Codex、Claude Code、Trae、Cursor 等 AI 工具调用 <code>bifrost</code>。</li><li>保持桌面端更新与 CLI 更新的边界清晰：桌面端使用 <code>bifrost app upgrade</code>，CLI 使用 <code>bifrost upgrade</code>。</li></ul><h3 id="cli-管理桌面端" tabindex="-1">CLI 管理桌面端 <a class="header-anchor" href="#cli-管理桌面端" aria-label="Permalink to &quot;CLI 管理桌面端&quot;">​</a></h3><p><code>bifrost app</code> 管理桌面端安装包，和 <code>bifrost upgrade</code> 的 CLI 更新语义分开：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p><code>bifrost app upgrade</code> 默认安装最新桌面包；如果检测到独立安装的 CLI，也会同步把 CLI 更新到最新版本。桌面端 UI 触发更新时会使用同一套 Web UI 进度窗口，显示下载、安装和重启进度，完成后自动重启桌面应用。</p><p>如果你先安装的是桌面端，也可以在桌面 Settings 的 <code>Desktop Proxy Core</code> 卡片里点击 <code>Install CLI &amp; Skills</code>。该按钮会把桌面端内置的 <code>bifrost</code> CLI 安装到用户命令行目录，并安装 Bifrost AI skills，方便 Codex、Claude Code、Trae、Cursor 等 AI 工具直接调用 <code>bifrost</code>。</p><p>浏览器打开的 CLI Web UI 不显示这个桌面专属按钮；只有 Tauri 桌面端会显示桌面安装、桌面更新和桌面重启相关操作。</p><h2 id="更新与卸载" tabindex="-1">更新与卸载 <a class="header-anchor" href="#更新与卸载" aria-label="Permalink to &quot;更新与卸载&quot;">​</a></h2><p>桌面端会自动检查更新。也可以使用 CLI 手动管理桌面端：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bifrost</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uninstall</span></span></code></pre></div><p>源码仓库中也提供统一卸载脚本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 卸载 CLI 和桌面应用</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./uninstall.sh</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 连同数据一起清理</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./uninstall.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --purge</span></span></code></pre></div><p><code>--purge</code> 会删除本地数据目录，包含规则、证书、日志和运行时状态。执行前请确认不需要保留现有配置。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="macos-提示无法打开或开发者无法验证" tabindex="-1">macOS 提示无法打开或开发者无法验证 <a class="header-anchor" href="#macos-提示无法打开或开发者无法验证" aria-label="Permalink to &quot;macOS 提示无法打开或开发者无法验证&quot;">​</a></h3><p>当前未签名构建可能触发 Gatekeeper。确认安装包来自官方 GitHub Releases 后，到 <code>System Settings -&gt; Privacy &amp; Security</code> 中允许打开。不要从未知镜像站下载安装包。</p><h3 id="windows-smartscreen-提示未知发布者" tabindex="-1">Windows SmartScreen 提示未知发布者 <a class="header-anchor" href="#windows-smartscreen-提示未知发布者" aria-label="Permalink to &quot;Windows SmartScreen 提示未知发布者&quot;">​</a></h3><p>确认文件来自官方 GitHub Releases，且文件名与目标架构匹配。企业环境中如果策略禁止未签名安装包，需要请管理员放行。</p><h3 id="启动后看不到流量" tabindex="-1">启动后看不到流量 <a class="header-anchor" href="#启动后看不到流量" aria-label="Permalink to &quot;启动后看不到流量&quot;">​</a></h3><p>确认桌面端后端已经启动，再检查系统代理、目标 App 是否走系统代理，以及是否需要开启 TLS 拦截。浏览器或 CLI 工具单独配置代理时，代理地址通常是 <code>127.0.0.1:9900</code>。</p><h3 id="https-抓包失败" tabindex="-1">HTTPS 抓包失败 <a class="header-anchor" href="#https-抓包失败" aria-label="Permalink to &quot;HTTPS 抓包失败&quot;">​</a></h3><p>先确认 Bifrost CA 已安装并被系统信任。部分 App 使用证书固定或自定义 TLS 栈，无法解密时应使用应用排除、域名排除或规则级 <code>tlsPassthrough://</code>，不要强行全局拦截。</p><h2 id="从源码构建" tabindex="-1">从源码构建 <a class="header-anchor" href="#从源码构建" aria-label="Permalink to &quot;从源码构建&quot;">​</a></h2><h3 id="使用安装脚本" tabindex="-1">使用安装脚本 <a class="header-anchor" href="#使用安装脚本" aria-label="Permalink to &quot;使用安装脚本&quot;">​</a></h3><p>在 macOS 上执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span></span></code></pre></div><p>默认行为：</p><ul><li>安装 <code>bifrost</code> CLI 到 <code>~/.local/bin</code></li><li>构建并安装 <code>Bifrost.app</code> 到 <code>/Applications/Bifrost.app</code></li></ul><p>可选参数：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --cli-only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --desktop-only</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --app-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Applications</span></span></code></pre></div><h3 id="手动构建" tabindex="-1">手动构建 <a class="header-anchor" href="#手动构建" aria-label="Permalink to &quot;手动构建&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/bifrost-proxy/bifrost.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bifrost</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> web</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> desktop:build</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 仅构建 macOS .app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> desktop:build:app</span></span></code></pre></div><p>产物位置：</p><ul><li>macOS <code>.dmg</code>：<code>desktop/src-tauri/target/release/bundle/dmg/</code></li><li>macOS <code>.app</code>：<code>desktop/src-tauri/target/release/bundle/macos/</code></li><li>Windows <code>.msi</code>：<code>desktop/src-tauri/target/release/bundle/msi/</code></li></ul>`,59)])])}const b=a(l,[["render",n]]);export{k as __pageData,b as default};
